### 1. **Shared Error Types & Factory** (`/data/projects/flywheel_gateway/packages/shared/src/errors/`)

#### Error Code Taxonomy (`codes.ts`)
The system uses a comprehensive error code taxonomy with automatic HTTP status mapping:

```typescript
export const ErrorCodes = {
  // Agent lifecycle
  AGENT_NOT_FOUND: { httpStatus: 404, message: "Agent not found" },
  AGENT_ALREADY_EXISTS: { httpStatus: 409, message: "Agent with this ID already exists" },
  AGENT_TIMEOUT: { httpStatus: 408, message: "Agent response timed out" },
  SPAWN_QUOTA_EXCEEDED: { httpStatus: 429, message: "Spawn quota exceeded" },

  // Rate limiting / quota
  RATE_LIMIT_EXCEEDED: { httpStatus: 429, message: "Rate limit exceeded" },
  QUOTA_EXCEEDED: { httpStatus: 429, message: "Quota exceeded" },

  // Authentication / authorization
  AUTH_TOKEN_INVALID: { httpStatus: 401, message: "Authentication token invalid" },
  AUTH_INSUFFICIENT_SCOPE: { httpStatus: 403, message: "Insufficient authorization scope" },

  // Validation
  INVALID_REQUEST: { httpStatus: 400, message: "Request validation failed" },
  VALIDATION_FAILED: { httpStatus: 400, message: "Validation failed" },
  // ... 50+ more codes
} as const;

export function getHttpStatus(code: ErrorCode): number {
  return ErrorCodes[code].httpStatus;
}
```

