#### AI Hints System (`ai-hints.ts`)
Context-aware hints for error recovery, organized by error pattern:

```typescript
const AI_HINT_OVERRIDES: Partial<Record<ErrorCode, AIHint>> = {
  AGENT_NOT_FOUND: {
    severity: "terminal",
    suggestedAction: "List active agents and use a valid agent ID.",
    alternativeApproach: "Spawn a new agent if the intended one was terminated.",
  },
  RATE_LIMIT_EXCEEDED: {
    severity: "retry",
    suggestedAction: "Wait before retrying the request.",
  },
  SPAWN_QUOTA_EXCEEDED: {
    severity: "recoverable",
    suggestedAction: "Terminate unused agents before spawning new ones.",
    alternativeApproach: "Request additional quota if more agents are required.",
  },
};

function defaultHintForCode(code: ErrorCode): AIHint {
  if (code.endsWith("_NOT_FOUND")) {
    return { severity: "terminal", suggestedAction: "Verify the identifier and retry..." };
  }
  if (code.endsWith("_ALREADY_EXISTS") || code.endsWith("_ALREADY_RUNNING")) {
    return { severity: "recoverable", suggestedAction: "Reuse the existing resource..." };
  }
  if (code.includes("RATE_LIMIT") || code.includes("QUOTA")) {
    return { severity: "retry", suggestedAction: "Back off and retry after a delay." };
  }
  // ... more patterns
}
