export function wrapError(options: WrapErrorOptions): ApiErrorResponse {
  // Automatically includes AI hints for known error codes
  const aiHint = AI_HINTS[options.code as ErrorCode];

  const error: ApiError = {
    code: options.code,
    message: options.message,
    severity: options.severity ?? aiHint?.severity,
    hint: options.hint ?? aiHint?.suggestedAction,
    alternative: options.alternative ?? aiHint?.alternativeApproach,
    // ...
  };

  return {
    object: "error",
    error,
    requestId: options.requestId ?? generateRequestId(),
    timestamp: options.timestamp ?? new Date().toISOString(),
  };
}

export function wrapValidationError(errors: Array<{ path: string; message: string; code?: string }>): ApiErrorResponse
