### 3. **Correlation ID Middleware** (`/data/projects/flywheel_gateway/apps/gateway/src/middleware/correlation.ts`)

Automatic request tracking and correlation:

```typescript
export interface RequestContext {
  correlationId: string;
  requestId: string;
  startTime: number;
  logger: Logger;
}

export const requestContextStorage = new AsyncLocalStorage<RequestContext>();

export function correlationMiddleware() {
  return async (c: Context, next: Next) => {
    const incomingCorrelationId = c.req.header("x-correlation-id");
    const correlationId = incomingCorrelationId || crypto.randomUUID();
    const requestId = crypto.randomUUID();
    const startTime = performance.now();

    const requestLogger = createChildLogger({
      correlationId,
      requestId,
      method: c.req.method,
      path: c.req.path,
    });

    const context: RequestContext = {
      correlationId,
      requestId,
      startTime,
      logger: requestLogger,
    };

    // Set response headers
    c.header("X-Correlation-ID", correlationId);
    c.header("X-Request-ID", requestId);
    c.set("correlationId", correlationId);
    c.set("requestId", requestId);

    // Propagate context through AsyncLocalStorage
    await requestContextStorage.run(context, async () => {
      await next();
    });
  };
}

export function getCorrelationId(): string {
  return getRequestContext()?.correlationId ?? "unknown";
}

export function getLogger(): Logger {
  return getRequestContext()?.logger ?? logger;
}
```

