### 4. **Response Helpers** (`/data/projects/flywheel_gateway/apps/gateway/src/utils/response.ts`)

Convenient route handlers with built-in correlation ID injection:

```typescript
// Single Resource
export function sendResource<T>(c: Context, objectType: string, data: T, status = 200, options = {}) {
  const requestId = getCorrelationId();
  return c.json(wrapResource(objectType, data, { ...options, requestId }), status);
}

// Created Resource (HTTP 201)
export function sendCreated<T>(c: Context, objectType: string, data: T, selfUrl: string, options = {}) {
  const requestId = getCorrelationId();
  return c.json(wrapCreated(objectType, data, selfUrl, { ...options, requestId }), 201);
}

// List Response
export function sendList<T>(c: Context, data: T[], options = {}) {
  const requestId = getCorrelationId();
  const url = new URL(c.req.url).pathname;
  return c.json(wrapList(data, { ...options, url, requestId }));
}

// Error Responses
export function sendError(c: Context, code: string, message: string, status: ContentfulStatusCode, options = {}) {
  const requestId = getCorrelationId();
  return c.json(wrapError({ code, message, ...options, requestId }), status);
}

export function sendNotFound(c: Context, resourceType: string, identifier: string) {
  const requestId = getCorrelationId();
  return c.json(wrapNotFound(resourceType, identifier, { requestId }), 404);
}

export function sendValidationError(c: Context, errors: Array<{ path: string; message: string; code?: string }>) {
  const requestId = getCorrelationId();
  return c.json(wrapValidationError(errors, { requestId }), 400);
}

export function sendInternalError(c: Context, message = "Internal server error") {
  const requestId = getCorrelationId();
  return c.json(
    wrapError({
      code: "INTERNAL_ERROR",
      message,
      requestId,
      severity: "retry",
      hint: "Retry the request. If the issue persists, contact support.",
    }),
    500,
  );
}

// Specialized errors
export function sendForbidden(c: Context, message = "Access denied")
export function sendUnauthorized(c: Context, message = "Authentication required")
export function sendConflict(c: Context, code: string, message: string, options = {})
export function sendNoContent(c: Context)
```

