### 5. **Route-Level Error Handling Patterns**

#### Pattern A: Route-Specific Error Class (`agents.ts`)
```typescript
export class AgentError extends Error {
  constructor(
    public code: string,
    message: string,
  ) {
    super(message);
    this.name = "AgentError";
  }
}

// Usage in services
throw new AgentError("AGENT_NOT_FOUND", `Agent ${agentId} not found`);
throw new AgentError("SPAWN_FAILED", `Failed to spawn agent: ${error}`);
```

#### Pattern B: Centralized Error Handler in Routes (`agents.ts`)
```typescript
function handleAgentError(error: unknown, c: Context) {
  const log = getLogger();

  // Handle custom errors
  if (error instanceof AgentError) {
    let httpStatus: ContentfulStatusCode = 500;
    try {
      const status = getHttpStatus(error.code as ErrorCode);
      if (status) httpStatus = status as ContentfulStatusCode;
    } catch {
      // Unknown error code, use 500
    }
    log.warn(
      { error: error.code, message: error.message },
      "Agent operation failed",
    );
    return sendError(c, error.code, error.message, httpStatus);
  }

  // Handle validation errors
  if (error instanceof z.ZodError) {
    return sendValidationError(c, transformZodError(error));
  }

  // Handle JSON parsing errors
  if (error instanceof SyntaxError && error.message.includes("JSON")) {
    return sendError(c, "INVALID_REQUEST", "Invalid JSON in request body", 400);
  }

  // Log unknown errors
  log.error({ error }, "Unexpected error in agent route");
  return sendInternalError(c);
}

// Usage in routes
agents.post("/", async (c) => {
  try {
    const body = await c.req.json();
    const validated = SpawnRequestSchema.parse(body);
    const result = await spawnAgent({ /* ... */ });
    return sendResource(c, "agent", result, 201, { links: agentLinks(/* ... */) });
  } catch (error) {
    return handleAgentError(error, c);
  }
});
```

#### Pattern C: Simple Error Handler (`checkpoints.ts`)
```typescript
function handleError(error: unknown, c: Context) {
  const log = getLogger();

  if (error instanceof CheckpointError) {
    const statusMap: Record<string, 400 | 404 | 500> = {
      CHECKPOINT_NOT_FOUND: 404,
      PARENT_NOT_FOUND: 404,
      CHECKPOINT_INVALID: 400,
      IMPORT_HASH_MISMATCH: 400,
    };
    const status = statusMap[error.code] ?? 500;
    return sendError(c, error.code, error.message, status);
  }

  if (error instanceof z.ZodError) {
    return sendValidationError(c, transformZodError(error));
  }

  if (error instanceof SyntaxError && error.message.includes("JSON")) {
    return sendError(c, "INVALID_REQUEST", "Invalid JSON in request body", 400);
  }

  log.error({ error }, "Unexpected error in checkpoint route");
  return sendInternalError(c);
}
```

