+// ============================================================================
+// Helper
+// ============================================================================
+
+fn write_json(dir: &Path, rel_path: &str, content: &str) -> std::path::PathBuf {
+    let path = dir.join(rel_path);
+    if let Some(parent) = path.parent() {
+        fs::create_dir_all(parent).unwrap();
+    }
+    fs::write(&path, content).unwrap();
+    path
+}
