+fn write_jsonl(dir: &Path, rel_path: &str, lines: &[&str]) -> std::path::PathBuf {
+    let path = dir.join(rel_path);
+    if let Some(parent) = path.parent() {
+        fs::create_dir_all(parent).unwrap();
+    }
+    fs::write(&path, lines.join("\n")).unwrap();
